    expect(result.content, contains('Alice'));
    expect(result.content, contains('30'));
    expect(result.content, contains('|'));
    expect(result.content, contains('---'));
  });

  test('Empty table produces no output or minimal output', () async {
    final _options = await createConversionOptionsFromJson(json: '{}');
    final result = await H2mBridge.convert('<table></table>', options: _options);
    expect(result.content.toString().trim(), equals(''.toString().trim()));
  });

  test('Table without thead uses first row as implied header', () async {
    final _options = await createConversionOptionsFromJson(json: '{}');
    final result = await H2mBridge.convert('<table><tr><td>Product</td><td>Price</td></tr><tr><td>Apple</td><td>1.00</td></tr></table>', options: _options);
    expect(result.content, isNotNull);
    expect(result.content, contains('Product'));
    expect(result.content, contains('Price'));
    expect(result.content, contains('Apple'));
    expect(result.content, contains('1.00'));
    expect(result.content, contains('|'));
  });

  test('Table cells containing pipe characters are escaped in output', () async {
    final _options = await createConversionOptionsFromJson(json: '{}');
    final result = await H2mBridge.convert('<table><thead><tr><th>Expression</th><th>Result</th></tr></thead><tbody><tr><td>a | b</td><td>true</td></tr></tbody></table>', options: _options);
    expect(result.content, isNotNull);
    expect(result.content, contains('Expression'));
    expect(result.content, contains('Result'));
    expect(result.content, contains('true'));
  });

  test('Table with column alignment attributes', () async {
    final _options = await createConversionOptionsFromJson(json: '{}');
    final result = await H2mBridge.convert('<table><thead><tr><th align="left">Left</th><th align="center">Center</th><th align="right">Right</th></tr></thead><tbody><tr><td>L</td><td>C</td><td>R</td></tr></tbody></table>', options: _options);
    expect(result.content, isNotNull);
    expect(result.content, contains('Left'));
    expect(result.content, contains('Center'));
    expect(result.content, contains('Right'));
    expect(result.content, contains('L'));
    expect(result.content, contains('C'));
    expect(result.content, contains('R'));
    expect(result.content, contains('|'));
  });

  test('Table with colspan attribute in a header cell', () async {
    final _options = await createConversionOptionsFromJson(json: '{}');
    final result = await H2mBridge.convert('<table><thead><tr><th colspan="2">Full Name</th></tr></thead><tbody><tr><td>John</td><td>Doe</td></tr></tbody></table>', options: _options);
    expect(result.content, isNotNull);
    expect(result.content, contains('Full Name'));
    expect(result.content, contains('John'));
    expect(result.content, contains('Doe'));
  });

  test('Unordered list', () async {
    final _options = await createConversionOptionsFromJson(json: '{}');
    final result = await H2mBridge.convert('<ul><li>Item 1</li><li>Item 2</li><li>Item 3</li></ul>', options: _options);
    expect(result.content, contains('- Item 1'));
    expect(result.content, contains('- Item 2'));
    expect(result.content, contains('- Item 3'));
  });

}
